import React from "react";
import { Link } from "gatsby";
import "./DharmaSupport.css";
import { useCMS } from "../../contexts/CMSContext";
import { STATIC_VIDEOS } from "../../contexts/db/videos";
import { STATIC_MUSIC_ALBUMS } from "../../contexts/db/music-albums";
import { STATIC_COLLECTIONS } from "../../contexts/db/collections";

const cleanImageUrl = (url?: string) => {
  if (!url) return url;
  // Remove WordPress image size suffix (e.g. -150x150, -300x200) to get original image
  return url.replace(/-(\d+)x(\d+)(\.[a-z0-9]+)$/i, '$3');
};

const extractFirstImage = (html?: string) => {
  if (!html) return null;
  
  // 1. Try to find high-res image link in anchor tags first (common WordPress pattern)
  const hrefMatch = html.match(/<a[^>]+href=["']([^"']+\.(?:jpg|jpeg|png|gif|webp))["']/i);
  if (hrefMatch) return cleanImageUrl(hrefMatch[1]);

  // 2. Fallback to img src
  const match = html.match(/<img[^>]+src="([^">]+)"/);
  if (!match) return null;
  return cleanImageUrl(match[1]);
};

const SupportCardContent: React.FC<{ item: any, type?: 'tv' | 'music' | 'support', isFeatured?: boolean }> = ({ item, type, isFeatured }) => {
  let thumbUrl: string | undefined = cleanImageUrl(item.image) || undefined;
  
  if (!thumbUrl) {
    if (type === 'tv' && item.videoId) {
      thumbUrl = isFeatured 
        ? `https://img.youtube.com/vi/${item.videoId}/maxresdefault.jpg` 
        : `https://img.youtube.com/vi/${item.videoId}/mqdefault.jpg`;
    } else if (type === 'tv' && (item.id || item.slug)) {
       const found = STATIC_VIDEOS.find((v: any) => v.id === item.id || v.slug === item.slug);
       if (found?.videoId) {
         thumbUrl = isFeatured 
           ? `https://img.youtube.com/vi/${found.videoId}/maxresdefault.jpg`
           : `https://img.youtube.com/vi/${found.videoId}/mqdefault.jpg`;
       }
    } else if (type === 'music' && (item.id || item.slug)) {
       // Search in all albums/tracks
       const foundAlbum = STATIC_MUSIC_ALBUMS.find((a: any) => a.id === item.id || a.slug === item.slug);
       if (foundAlbum?.thumbnail) {
         thumbUrl = cleanImageUrl(foundAlbum.thumbnail) || undefined;
       } else {
         const foundTrack = STATIC_MUSIC_ALBUMS.flatMap(a => a.tracks || []).find((t: any) => t.id === item.id || t.slug === item.slug);
         if (foundTrack?.image) {
           thumbUrl = cleanImageUrl(foundTrack.image) || undefined;
         } else if (foundTrack?.imageFile) {
           // Fallback to imageFile if possible - assuming it's in a known path
           thumbUrl = `https://bodephatquoc.org/wp-content/uploads/${foundTrack.imageFile}`;
         }
       }
    } else if (type === 'support' && (item.id || item.slug)) {
       const found = STATIC_COLLECTIONS.find((c: any) => c.id === item.id || c.slug === item.slug);
       if (found?.image) {
         thumbUrl = cleanImageUrl(found.image) || undefined;
       } else if (found?.body) {
         // Extract first image from body if 'image' is empty
         thumbUrl = extractFirstImage(found.body) || undefined;
       }
    }
  }

  return (
    <>
      <div className="support-thumb">
        {thumbUrl ? (
          <img
            src={thumbUrl}
            alt={item.title}
            onError={(e) => (e.currentTarget.style.display = 'none')}
          />
        ) : (
          <div className="thumb-placeholder">
            {type === 'music' ? (
              <span style={{ fontSize: '32px' }}>🎵</span>
            ) : type === 'support' ? (
              <span style={{ fontSize: '32px' }}>📷</span>
            ) : (
              <svg
                xmlns="http://www.w3.org/2000/svg"
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                strokeWidth="1"
              >
                <rect x="3" y="3" width="18" height="18" rx="2" ry="2" />
                <circle cx="8.5" cy="8.5" r="1.5" />
                <polyline points="21 15 16 10 5 21" />
              </svg>
            )}
          </div>
        )}
      </div>
      <p>{item.title}</p>
    </>
  );
};

const SupportSection: React.FC = () => {
  const { displayData } = useCMS();
  const support = displayData.pages.home.supportContent;

  if (!support) return null;

  return (
    <section
      id="HỘ-TRÌ-CHÁNH-PHÁP"
      className="support-section"
      style={{
        '--bg-desktop': `url(${support.backgroundImage})`,
        '--bg-mobile': `url(${support.mobileBackgroundImage})`
      } as React.CSSProperties}
    >
      <div className="support-overlay" />

      <div className="support-container">
        {/* Section header */}
        <div className="support-header" data-aos="fade-up">
          <h2>
            {support.sectionTitle.split("\n").map((line, i) => (
              <React.Fragment key={i}>
                {line}
                <br />
              </React.Fragment>
            ))}
          </h2>
          <div className="support-underline" />
        </div>

        {/* Columns */}
        <div className="support-columns">
          {support.columns.map((column, colIndex) => (
            <div
              key={column.id}
              className="support-column"
              data-aos="fade-up"
              data-aos-delay={100 * (colIndex + 1)}
            >
              <h3>{column.title}</h3>

              {column.items.map((item, itemIndex) => {
                const isVideo = column.id === 'tv' || item.link?.includes('/videos') || item.videoId;
                const isMusic = column.id === 'music' || item.link?.includes('/music');
                const isGallery = column.id === 'support' || item.link?.includes('/galleries');

                let linkTo = item.link || '#';

                if (isVideo && (item.slug || item.id || item.videoId)) {
                  linkTo = item.slug ? `/video/${item.slug}` : `/video/${item.id || item.videoId}`;
                } else if (isMusic && (item.slug || item.id)) {
                  linkTo = `/music/${item.slug || item.id}`;
                } else if (isGallery && (item.slug || item.id)) {
                  linkTo = `/collection/${item.slug || item.id}`;
                } else if (item.id && !item.link) {
                   linkTo = `/support/${item.id}`;
                }

                if (linkTo === '#') {
                  return (
                    <div key={item.id || itemIndex} className={`support-card no-link ${column.id === 'tv' && itemIndex === 0 ? 'featured-card' : ''}`}>
                      <SupportCardContent item={item} type={column.id as any} isFeatured={column.id === 'tv' && itemIndex === 0} />
                    </div>
                  );
                }
                return (
                  <Link
                    to={linkTo}
                    key={item.id || itemIndex}
                    className={`support-card ${column.id === 'tv' && itemIndex === 0 ? 'featured-card' : ''}`}
                    data-aos="fade-up"
                    data-aos-delay={200 + itemIndex * 100}
                  >
                    <SupportCardContent item={item} type={column.id as any} isFeatured={column.id === 'tv' && itemIndex === 0} />
                  </Link>
                );
              })}
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default SupportSection;
