import React from "react";
import { Link } from "gatsby";
import "./library.css";
import { useCMS } from "../../contexts/CMSContext";

const ScriptureSection: React.FC = () => {
  const { displayData } = useCMS();
  const scripture = displayData.pages.home.scriptureContent;

  const renderItemLink = (item: { id: string; label: string; href?: string }) => {
    const className = "scripture-item-link";
    const labelForSearch = item.label.replace(/ ›$/, '').trim();
    
    // Smart routing based on common video keywords
    const videoKeywords = ['Nghiêm', 'Pháp Hoa', 'Niết Bàn', 'Sám', 'Duy Ma Cật', 'Vô Lượng Thọ', 'Tương Ưng Bộ', 'Trường Bộ', 'Tăng Nhất A Hàm', 'Tạp A Hàm', 'Trung Bộ', 'Dược Sư', 'Địa Tạng', 'Đại Bi', 'Cận tử'];
    const isLikelyVideo = videoKeywords.some(kw => labelForSearch.includes(kw));
    
    const fallbackHref = isLikelyVideo 
      ? `/videos#${encodeURIComponent(labelForSearch)}`
      : `/education#${encodeURIComponent(labelForSearch)}`;
    
    const finalHref = (!item.href || item.href === "#") ? fallbackHref : item.href;

    if (finalHref.startsWith("/")) {
      return (
        <Link to={finalHref} className={className}>
          {item.label}
        </Link>
      );
    }

    const isExternalUrl = /^https?:\/\//i.test(finalHref);
 
    return (
      <a
        href={finalHref}
        className={className}
        {...(isExternalUrl ? { target: "_blank", rel: "noreferrer" } : {})}
      >
        {item.label}
      </a>
    );
  };

  if (!scripture) return null;

  return (
    <section
      id="THƯ-VIỆN"
      className="scripture"
      style={{ "--scripture-bg": `url(${scripture.backgroundImage}${scripture.backgroundImage.includes('?') ? '&' : '?'}tr=w-1920,q-80)` } as React.CSSProperties}
    >
      <div className="scripture-bg-overlay" />

      <div className="scripture-inner">
        {/* Header */}
        <div className="support-header2" data-aos="fade-up">
          <h2>
            {scripture.sectionTitle.split("\n").map((line, index) => (
              <React.Fragment key={index}>
                {line}
                <br />
              </React.Fragment>
            ))}
          </h2>
        </div>

        <div className="scripture-title-line" />

        {/* Cards */}
        <div className="scripture-grid">
          {scripture.cards.map((card, cardIndex) => (
            <div
              key={card.id}
              className="scripture-card"
              data-aos="fade-up"
              data-aos-delay={100 * (cardIndex + 1)}
            >
              <h3>{card.title}</h3>

              {card.groups.map(group => (
                <React.Fragment key={group.id}>
                  {group.title && (
                    <h4>
                      {group.title.split("\n").map((line, index) => (
                        <React.Fragment key={index}>
                          {line}
                          <br />
                        </React.Fragment>
                      ))}
                    </h4>
                  )}

                  <ul>
                    {group.items.map(item => (
                      <li key={item.id}>{renderItemLink(item)}</li>
                    ))}
                  </ul>
                </React.Fragment>
              ))}
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default ScriptureSection;
