import React, { useState, useEffect, useRef } from 'react';
import { Link } from 'gatsby';
import './new.css';
import { useCMS } from '../../contexts/CMSContext';
import videojs from "video.js";
import "video.js/dist/video-js.css";
import LiveStreamPlayer, { LiveStreamPlayerExample } from '../../components/LiveStreamPlayer';

interface AnnouncementsProps {
  featuredOnly?: boolean;
}

const FORCE_LIVE = true;

const LiveVideoPlayer: React.FC<{ src: string }> = ({ src }) => {
  const videoRef: any = useRef(null);
  const playerRef: any = useRef(null);

  useEffect(() => {
    if (!playerRef.current && videoRef.current) {
      playerRef.current = videojs(videoRef.current, {
        autoplay: true,
        controls: true,
        fluid: true,
        liveui: true,
        sources: [
          {
            src,
            type: "application/x-mpegURL",
          },
        ],
      });
    }

    return () => {
      if (playerRef.current) {
        playerRef.current.dispose();
        playerRef.current = null;
      }
    };
  }, [src]);

  return (
    <div data-vjs-player>
      <video
        ref={videoRef}
        className="video-js vjs-big-play-centered"
      />
    </div>
  );
};

const AnnouncementContent: React.FC<{ item: any }> = ({ item }) => (
  <>
    <div className="announcement-thumb">
      {item.image ? (
        <img
          src={item.image}
          alt={item.title}
          className="thumb-img"
          onError={(e) => {
            e.currentTarget.style.display = 'none';
            const parent = e.currentTarget.parentElement;
            if (parent) {
              parent.classList.add('no-image');
            }
          }}
        />
      ) : null}
      <div className="thumb-fallback">
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1">
          <path d="M4 12V4a2 2 0 0 1 2-2h12a2 2 0 0 1 2 2v16a2 2 0 0 1-2 2H6a2 2 0 0 1-2-2v-4" />
          <polyline points="10 9 15 12 10 15" />
        </svg>
      </div>
    </div>

    <div className="announcement-text">
      <h4 className="announcement-title">{item.title}</h4>
      <p className="announcement-description">{item.cleanSubtitle}</p>
    </div>
  </>
);

const Announcements: React.FC<AnnouncementsProps> = ({ featuredOnly = false }) => {
  const { displayData } = useCMS();
  const { newsContent, supportContent } = displayData?.pages?.home || {};
  const [isPlaying, setIsPlaying] = useState(false);

  const tvSection = supportContent?.columns.find((c: any) => c.id === 'tv');
  const firstTvItem : any = tvSection?.items?.[0];

  const tvLink = (firstTvItem?.slug || firstTvItem?.id)
    ? (firstTvItem.slug ? `/video/${firstTvItem.slug}` : `/video/${firstTvItem.id}`)
    : (firstTvItem?.link || '/videos');

  const tvTitle = tvSection?.title || 'BỒ ĐỀ PHẬT QUỐC TV 57.15';
  const tvDescription = "Xem trực tiếp và các chương trình hoằng pháp";

  const extractFirstImage = (body: string) => {
    if (!body) return null;
    const imgMatch = body.match(/src=["']([^"']+\.(?:jpg|jpeg|png|gif|webp|bmp))["']/i);
    let imageUrl = imgMatch ? imgMatch[1] : null;

    if (imageUrl) {
      imageUrl = imageUrl.replace(
        /http:\/\/bodephatquoc\.org\/wp-content\/uploads\//g, 
        'https://ik.imagekit.io/dloitl7fd8/wp-content/uploads/'
      );
    }
    return imageUrl;
  };

  const stripHtml = (html: string) => {
    if (!html) return '';
    return html.replace(/<[^>]*>?/gm, '').replace(/&nbsp;/g, ' ').trim();
  };

  const announcements = (newsContent.items || []).map((item: any) => ({
    ...item,
    image: item.image || extractFirstImage(item.body),
    cleanSubtitle: item.subtitle || stripHtml(item.excerpt || item.body || '').substring(0, 150)
  }));

  if (!announcements || announcements.length === 0) return null;

  return (
    <section className="announcements-section">
      <div className="announcements-container">
        <div className="announcements-grid">

          {/* LEFT column */}
          <div className="announcements-featured">

            {FORCE_LIVE ? (
              <LiveStreamPlayerExample />
            ) : (
              isPlaying ? (
                <div className="featured-video-container">

                  {firstTvItem?.videoType === "live" ? (
                    <LiveVideoPlayer
                      src={firstTvItem?.liveUrl || "https://live.bodephatquoc.org/bdpq/kenh1/playlist.m3u8"}
                    />
                  ) : firstTvItem?.videoId ? (
                    <iframe
                      src={`https://www.youtube.com/embed/${firstTvItem.videoId}?autoplay=1`}
                      title="YouTube video player"
                      allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
                      allowFullScreen
                    ></iframe>
                  ) : null}

                </div>
              ) : (
                <div
                  className="featured-interactive-area"
                  onClick={() => setIsPlaying(true)}
                  style={{ cursor: 'pointer' }}
                >
                  <div className="featured-image">
                    {firstTvItem?.image ? (
                      <img
                        src={firstTvItem.image}
                        alt={firstTvItem.title}
                        className="featured-img"
                      />
                    ) : firstTvItem?.videoId ? (
                      <img
                        src={`https://img.youtube.com/vi/${firstTvItem.videoId}/maxresdefault.jpg`}
                        alt={firstTvItem.title}
                        className="featured-img"
                      />
                    ) : (
                      <div className="image-placeholder">
                        <div className="placeholder-content">
                          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5">
                            <path d="M21 12a9 9 0 11-18 0 9 9 0 0 1 18 0z" />
                            <path d="M15.91 11.672a.375.375 0 0 1 0 .656l-5.603 3.113a.375.375 0 0 1-.557-.328V8.887c0-.286.307-.466.557-.327l5.603 3.112z" />
                          </svg>
                          <span>PHẬT QUỐC TV</span>
                        </div>
                      </div>
                    )}
                    {firstTvItem?.videoId && (
                      <div className="featured-video-overlay">
                        <button className="play-video-button">▶</button>
                      </div>
                    )}
                  </div>
                  
                </div>
              )
            )}

          </div>

          {/* RIGHT column (unchanged) */}
          <div className="announcements-list">
            <div className="list-header">
              <h2 className="section-title">{newsContent.sectionTitle}</h2>
              <div className="title-underline"></div>
            </div>

            <div className="announcements-items">
              {announcements.slice(0, 3).map((item) => {
                const isExternal = item.link?.startsWith('http');

                const isGeneric = !item.link || item.link === '/videos' || item.link === '/video' || item.link === '#';
                const linkTo = item.isExternal || item.link?.startsWith('http')
                  ? (item.link || '#') 
                  : (isGeneric && (item.slug || item.id))
                    ? (item.slug ? `/video/${item.slug}` : `/video/${item.id}`)
                    : (item.link || '#');

                if (linkTo === '#' || (!item.slug && !item.id && !item.link)) {
                  return null;
                }

                return (
                  <div className="announcement-item" key={item.id}>
                    {isExternal ? (
                      <a href={linkTo} className="announcement-item-link">
                        <AnnouncementContent item={item} />
                      </a>
                    ) : (
                      <Link to={linkTo} className="announcement-item-link">
                        <AnnouncementContent item={item} />
                      </Link>
                    )}
                  </div>
                );
              })}
            </div>

            <div className="view-all-container">
              <a href="/news" className="view-all-link">
                Xem tất cả bản tin
                <svg className="view-all-arrow" width="20" height="20" viewBox="0 0 24 24">
                  <path d="M5 12h14M12 5l7 7-7 7" />
                </svg>
              </a>
              
            </div>
            
          </div>
          <div    className="news-toggle-label-hint" style={{ marginTop : -40 }}>SBU TV 57-15</div>
        </div>
      </div>
    </section>
  );
};

export default Announcements;